// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// STRY0100152 
	if(isLoading){
		setWarningMessage(newValue);
		return;
	}

	setWarningMessage();
	function setWarningMessage(newValue){

		g_form.showFieldMsg('warning_hours', getMessage('Set number of days from {0} that you want a reminder sent').replace('{0}',g_scratchpad.suspense_date_label), 'info', false); 		
	}
}
